function createBaseDynamicValue(): DynamicValue {
  return { msgpack: new Uint8Array(0), json: new Uint8Array(0) };
}

export const DynamicValue: MessageFns<DynamicValue> = {
  encode(message: DynamicValue, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.msgpack.length !== 0) {
      writer.uint32(10).bytes(message.msgpack);
    }
    if (message.json.length !== 0) {
      writer.uint32(18).bytes(message.json);
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): DynamicValue {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseDynamicValue();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 10) {
            break;
          }

          message.msgpack = reader.bytes();
          continue;
        }
        case 2: {
          if (tag !== 18) {
            break;
          }

          message.json = reader.bytes();
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  fromJSON(object: any): DynamicValue {
    return {
      msgpack: isSet(object.msgpack) ? bytesFromBase64(object.msgpack) : new Uint8Array(0),
      json: isSet(object.json) ? bytesFromBase64(object.json) : new Uint8Array(0),
    };
  },

  toJSON(message: DynamicValue): unknown {
    const obj: any = {};
    if (message.msgpack.length !== 0) {
      obj.msgpack = base64FromBytes(message.msgpack);
    }
    if (message.json.length !== 0) {
      obj.json = base64FromBytes(message.json);
    }
    return obj;
  },

  create<I extends Exact<DeepPartial<DynamicValue>, I>>(base?: I): DynamicValue {
    return DynamicValue.fromPartial(base ?? ({} as any));
  },
  fromPartial<I extends Exact<DeepPartial<DynamicValue>, I>>(object: I): DynamicValue {
    const message = createBaseDynamicValue();
    message.msgpack = object.msgpack ?? new Uint8Array(0);
    message.json = object.json ?? new Uint8Array(0);
    return message;
  },
};

function createBaseDiagnostic(): Diagnostic {
  return { severity: 0, summary: "", detail: "", attribute: undefined };
}

export const Diagnostic: MessageFns<Diagnostic> = {
  encode(message: Diagnostic, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.severity !== 0) {
      writer.uint32(8).int32(message.severity);
    }
    if (message.summary !== "") {
      writer.uint32(18).string(message.summary);
    }
    if (message.detail !== "") {
      writer.uint32(26).string(message.detail);
    }
    if (message.attribute !== undefined) {
      AttributePath.encode(message.attribute, writer.uint32(34).fork()).join();
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): Diagnostic {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseDiagnostic();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 8) {
            break;
          }

          message.severity = reader.int32() as any;
          continue;
        }
        case 2: {
          if (tag !== 18) {
            break;
          }

          message.summary = reader.string();
          continue;
        }
        case 3: {
          if (tag !== 26) {
            break;
          }

          message.detail = reader.string();
          continue;
        }
        case 4: {
          if (tag !== 34) {
            break;
          }

          message.attribute = AttributePath.decode(reader, reader.uint32());
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  fromJSON(object: any): Diagnostic {
    return {
      severity: isSet(object.severity) ? diagnostic_SeverityFromJSON(object.severity) : 0,
      summary: isSet(object.summary) ? globalThis.String(object.summary) : "",
      detail: isSet(object.detail) ? globalThis.String(object.detail) : "",
      attribute: isSet(object.attribute) ? AttributePath.fromJSON(object.attribute) : undefined,
    };
  },

  toJSON(message: Diagnostic): unknown {
    const obj: any = {};
    if (message.severity !== 0) {
      obj.severity = diagnostic_SeverityToJSON(message.severity);
    }
    if (message.summary !== "") {
      obj.summary = message.summary;
    }
    if (message.detail !== "") {
      obj.detail = message.detail;
    }
    if (message.attribute !== undefined) {
      obj.attribute = AttributePath.toJSON(message.attribute);
    }
    return obj;
  },

  create<I extends Exact<DeepPartial<Diagnostic>, I>>(base?: I): Diagnostic {
    return Diagnostic.fromPartial(base ?? ({} as any));
  },
  fromPartial<I extends Exact<DeepPartial<Diagnostic>, I>>(object: I): Diagnostic {
    const message = createBaseDiagnostic();
    message.severity = object.severity ?? 0;
    message.summary = object.summary ?? "";
    message.detail = object.detail ?? "";
    message.attribute = (object.attribute !== undefined && object.attribute !== null)
      ? AttributePath.fromPartial(object.attribute)
      : undefined;
    return message;
  },
};

